const statusData = $('Verificar Estado Google').first().json;
const rowsData = $('Obtener Citas del Cliente').first().json;
const input = $('Cuando lo llama el Router').first().json;

const userCitas = (rowsData.rows || [])
  .map(r => `- ${r[0]} ${r[1]}: ${r[4] || 'cita'} (${r[5] || 'Confirmada'})`);

const now = new Date();
const todayDate = now.toISOString().split('T')[0];
const mañana = new Date(now.getTime() + 86400000).toISOString().split('T')[0];
const diasSemana = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
const diaActual = diasSemana[now.getDay()];
const hora = now.toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Bogota' });

const rawSystemMessage = `Eres el asistente de agendamiento de ${input.businessName || 'este negocio'}.
Fecha y hora actual: ${todayDate} (${diaActual}) a las ${hora}.
Mañana: ${mañana}

CITAS CONFIRMADAS DE ESTE CLIENTE (${input.phone}):
${userCitas.length > 0 ? userCitas.join('\n') : 'Sin citas activas'}

RESPONDE SIEMPRE EN DOS PARTES:
1. Un mensaje natural y amigable para el cliente.
2. En la última línea, un objeto JSON sin markdown:
{"action":"<agendar|disponibilidad|mis_citas|cancelar|responder>","eventData":{"fecha":"YYYY-MM-DD","hora":"HH:MM","horaFin":"HH:MM","servicio":"...","nombre":"..."}}

REGLAS:
- Si el cliente quiere AGENDAR: extrae fecha, hora inicio, hora fin (default: hora inicio +1h), servicio y nombre. Si falta algún dato, usa action 'responder' y pídelo.
- Si el cliente quiere VER SUS CITAS: action 'mis_citas', eventData null.
- Si pregunta DISPONIBILIDAD: action 'disponibilidad', eventData null.
- Si quiere CANCELAR: action 'cancelar', eventData null.
- Para cualquier otra respuesta: action 'responder', eventData null.
- Cuando eventData no aplica, escribe exactamente: "eventData":null`;

// Escapar { y } para LangChain PromptTemplate (igual que el Router)
const systemMessage = rawSystemMessage.split('{').join('{{').split('}').join('}}');

return [{ json: {
  message: input.message || '',
  systemMessage,
  tenantId: input.tenantId,
  calendarId: statusData.calendarId || 'primary',
  phone: input.phone || '',
  pushName: input.pushName || 'Cliente',
  businessName: input.businessName || '',
  todayDate,
  userCitas
}}];

const agentOutput = ($input.first().json.output || '').trim();
const ctx = $('Preparar Contexto del Agente').first().json;

let action = 'responder';
let response = agentOutput;
let eventData = null;

// Buscar el JSON estructurado en la última línea del output
const lines = agentOutput.split('\n');
let jsonStr = null;
for (let i = lines.length - 1; i >= 0; i--) {
  const line = lines[i].trim();
  if (line.startsWith('{') && line.includes('"action"')) {
    jsonStr = line;
    break;
  }
}
// Si no encontramos en líneas, buscar con regex
if (!jsonStr) {
  const match = agentOutput.match(/\{[^\n]*"action"[^\n]*\}(?=[^{]*$)/);
  if (match) jsonStr = match[0];
}

if (jsonStr) {
  try {
    const parsed = JSON.parse(jsonStr);
    action = parsed.action || 'responder';
    eventData = parsed.eventData || null;
    // Limpiar el JSON del texto de respuesta
    response = agentOutput.replace(jsonStr, '').trim();
  } catch(e) {
    // Si no parsea, usar el output completo
  }
}

return [{ json: {
  action,
  response: response || agentOutput,
  eventData,
  tenantId: ctx.tenantId,
  calendarId: ctx.calendarId,
  phone: ctx.phone,
  pushName: ctx.pushName,
  todayDate: ctx.todayDate
}}];

